import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface SunriseSunsetData {
  location: string;
  current: {
    sunrise: string;
    sunset: string;
    dayLength: string;
    goldenHourStart: string;
    goldenHourEnd: string;
  };
}

export default function Widget() {
  const sunriseSunsetData = response.data as SunriseSunsetData;
  const { location, current } = sunriseSunsetData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 300,
        maxWidth: 400,
        bgcolor: 'rgba(255,255,255,0.7)',
        backdropFilter: 'blur(8px)',
        borderRadius: 2,
        boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFA726' }}>
              Sun Cycle Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Location: {location}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1.5}>
            <Chip
              label={`Sunrise: ${current.sunrise}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFCC80' }}
            />
            <Chip
              label={`Sunset: ${current.sunset}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFCC80' }}
            />
          </Stack>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Day Length: {current.dayLength}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1.5}>
            <Chip
              label={`Golden Hour Start: ${current.goldenHourStart}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFCC80' }}
            />
            <Chip
              label={`Golden Hour End: ${current.goldenHourEnd}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFCC80' }}
            />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
